const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };

const validTypes = ['kyc','suitability','disclosure','final_compliance'];
const reviewType = body.review_type;
if (validTypes.indexOf(reviewType) < 0) return { json: { _empty: true, error: 'review_type must be one of ' + validTypes.join(',') } };

// Caller passes the entity id appropriate for review_type.
const entityId =
  reviewType === 'kyc'              ? body.kyc_id :
  reviewType === 'suitability'      ? body.suitability_id :
  reviewType === 'disclosure'       ? body.disclosure_id :
  /* final_compliance */              body.policy_application_id;

if (!entityId) return { json: { _empty: true, error: 'entity id required for review_type=' + reviewType } };

return { json: {
  _authorized: true,
  review_type: reviewType,
  entity_id: entityId,
  policy_application_id: body.policy_application_id || null,
  client_id: body.client_id || null,
  advisor_id: body.advisor_id || null,
  vertical_id: 'insurance'
} };

// Build the per-review-type Claude prompt. Claude returns a structured
// regulated-decision JSON. Universal multi-vertical at platform level —
// this module is INSURANCE-vertical specific via vertical_id='insurance'.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const kycRows = allOf('Fetch KYC');
const suitRows = allOf('Fetch Suitability');
const discRows = allOf('Fetch Disclosure');
const appRows = allOf('Fetch Application');
const kyc = kycRows[0] || null;
const suit = suitRows[0] || null;
const disc = discRows[0] || null;
const app = appRows[0] || null;
const ctx = $('Validate').item.json;

const commonHeader = [
  'You are the Crystallux AI Compliance Agent for the INSURANCE vertical (vertical_id=insurance).',
  'Regulatory framework: FSRA Ontario insurance regulation, PIPEDA (federal privacy), CASL (Canadian anti-spam), consumer-protection rules for replacement / suitability.',
  'You DO NOT have authority to bind the MGA. Your decision feeds a human compliance officer who can override.',
  '',
  'Output strictly JSON. Schema:',
  '{',
  '  "ai_decision":  "approved" | "flagged" | "rejected" | "requires_human_review",',
  '  "ai_score":     <integer 0-100, your confidence>,',
  '  "ai_reasoning": "<2-4 sentences explaining the decision>",',
  '  "flags":        [ "<short label per concrete issue>" ]',
  '}',
  '',
  'Decision rules:',
  '- approved: clean, all checks pass, no concerns.',
  '- flagged: minor issues — proceed with attention; flags array names them.',
  '- requires_human_review: any high-sensitivity case (PEP/AML signal, replacement, large coverage > $1M, vulnerable client indicators, missing required disclosure).',
  '- rejected: the application/document violates a hard regulatory requirement.',
  '- ALWAYS choose requires_human_review when uncertain. Never auto-approve at low confidence.'
].join('\n');

let typeBlock = '';
let sourceData = {};

if (ctx.review_type === 'kyc' && kyc) {
  typeBlock = [
    'Review type: KYC verification.',
    'Required checks: identity match, document validity, expiry, AML risk, PEP screening, jurisdiction (Canadian residency for FSRA-regulated business).',
    'Selfie match below 0.85 = flag. AML risk > 75 = requires_human_review. PEP positive = requires_human_review.'
  ].join('\n');
  sourceData = {
    status: kyc.status,
    selfie_match_score: kyc.selfie_match_score,
    aml_risk_score: kyc.aml_risk_score,
    pep_screening_result: kyc.pep_screening_result,
    has_identity_data: !!kyc.identity_data,
    verification_provider: kyc.verification_provider
  };
} else if (ctx.review_type === 'suitability' && suit) {
  typeBlock = [
    'Review type: Suitability assessment.',
    'Required checks: client_situation captured (income/dependents/existing coverage/health), needs_analysis derived logically, recommended product matches stated needs, recommended coverage proportional to income/dependents, replacement disclosure present if applicable.'
  ].join('\n');
  sourceData = {
    product_type: suit.product_type,
    client_situation_keys: Object.keys(suit.client_situation || {}),
    needs_analysis: suit.needs_analysis,
    risk_tolerance: suit.risk_tolerance,
    ai_recommended_coverage_amount_cents: suit.ai_recommended_coverage_amount,
    ai_recommended_term_years: suit.ai_recommended_term_years,
    client_acknowledged: suit.client_acknowledged
  };
} else if (ctx.review_type === 'disclosure' && disc) {
  typeBlock = [
    'Review type: Disclosure acknowledgment.',
    'Required checks: presented_at recorded, acknowledged_at present (if signed), method matches type, expiry not passed, content_template_id matches an approved template, esignature_id present for esignature method.'
  ].join('\n');
  sourceData = {
    disclosure_type: disc.disclosure_type,
    presented_at: disc.presented_at,
    acknowledged_at: disc.acknowledged_at,
    acknowledgment_method: disc.acknowledgment_method,
    has_esignature_id: !!disc.esignature_id,
    has_signed_doc: !!disc.signed_document_url,
    expires_at: disc.expires_at
  };
} else if (ctx.review_type === 'final_compliance' && app) {
  typeBlock = [
    'Review type: FINAL pre-submission compliance review.',
    'Required checks: KYC verified, suitability completed AND client_acknowledged, all required disclosures signed, no fields_requiring_human_input outstanding, advisor_review_status=approved, application_data structurally complete for the carrier.',
    'Default to requires_human_review unless you have strong evidence ALL checks pass. This is the last gate before submission.'
  ].join('\n');
  sourceData = {
    advisor_review_status: app.advisor_review_status,
    submission_status: app.submission_status,
    has_application_data: !!(app.application_data && Object.keys(app.application_data).length),
    fields_requiring_human_input_count: Array.isArray(app.fields_requiring_human_input) ? app.fields_requiring_human_input.length : 0,
    has_suitability: !!app.suitability_assessment_id,
    has_recommendation: !!app.policy_recommendation_id,
    carrier_name: app.carrier_name
  };
} else {
  return { json: { _not_found: true, error: 'entity not found for review_type=' + ctx.review_type, vertical_id: 'insurance' } };
}

const userPrompt = JSON.stringify({ review_type: ctx.review_type, vertical_id: 'insurance', source_data: sourceData });

return { json: {
  _ready: true,
  review_type: ctx.review_type,
  entity_id: ctx.entity_id,
  policy_application_id: ctx.policy_application_id || (app && app.id) || null,
  client_id: ctx.client_id || (kyc && kyc.client_id) || (suit && suit.client_id) || (disc && disc.client_id) || (app && app.client_id) || null,
  advisor_id: ctx.advisor_id || (suit && suit.advisor_id) || (app && app.advisor_id) || null,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 700,
    temperature: 0.1,
    system: commonHeader + '\n\n' + typeBlock,
    messages: [ { role: 'user', content: userPrompt } ]
  }
} };

const ctx = $('Build Claude Prompt').item.json;
const resp = $input.item.json || {};
let textOut = '';
try { textOut = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(textOut).replace(/```json|```/g, '').trim()); } catch (e) {}
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

if (!parsed) {
  // Fail-safe: defer to human if Claude failed.
  parsed = { ai_decision: 'requires_human_review', ai_score: 0, ai_reasoning: 'AI compliance check failed to produce a parseable decision. Defaulting to human review.', flags: ['ai_parse_failure'] };
}
const validDecisions = ['approved','flagged','rejected','requires_human_review'];
if (validDecisions.indexOf(parsed.ai_decision) < 0) parsed.ai_decision = 'requires_human_review';
parsed.ai_score = Math.min(Math.max(parseInt(parsed.ai_score) || 0, 0), 100);

const status = (parsed.ai_decision === 'approved') ? 'approved' :
               (parsed.ai_decision === 'rejected') ? 'rejected' :
               (parsed.ai_decision === 'requires_human_review') ? 'human_review_required' :
               'ai_reviewed';

return { json: {
  insert_row: {
    vertical_id: 'insurance',
    policy_application_id: ctx.policy_application_id,
    client_id: ctx.client_id,
    advisor_id: ctx.advisor_id,
    review_type: ctx.review_type,
    ai_score: parsed.ai_score,
    ai_decision: parsed.ai_decision,
    ai_reasoning: parsed.ai_reasoning || '',
    ai_flags: parsed.flags || [],
    status: status
  },
  needs_human: status === 'human_review_required',
  client_id: ctx.client_id,
  advisor_id: ctx.advisor_id,
  review_type: ctx.review_type,
  entity_id: ctx.entity_id,
  tokens: tokens
} };
